/**
 * DownloadService.ts
 *
 * Provides downloadPosterAsPDF() and downloadPosterAsDoc() utilities.
 * PDF is generated by walking the poster DOM and drawing it with jsPDF.
 * Word (.doc) is an HTML-blob opened as application/msword.
 */
import jsPDF from 'jspdf';
import type { CollegeEvent } from '../../../store/eventStore';

// ── PDF via jsPDF html() method ───────────────────────────────────────────────

export async function downloadPosterAsPDF(
  posterElement: HTMLElement,
  event: Pick<CollegeEvent, 'title'>,
): Promise<void> {
  const { default: html2canvas } = await import(
    /* webpackChunkName: "html2canvas" */ 'html2canvas'
  ).catch(() => ({ default: null as any }));

  if (html2canvas) {
    // Use html2canvas if available (best quality)
    const canvas = await html2canvas(posterElement, {
      scale: 2,
      useCORS: true,
      backgroundColor: null,
    });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
    const pdfW = pdf.internal.pageSize.getWidth();
    const pdfH = (canvas.height * pdfW) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfW, pdfH);
    pdf.save(`${sanitise(event.title)}_poster.pdf`);
    return;
  }

  // Fallback: plain text PDF with jsPDF
  const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  pdf.setFillColor(30, 27, 75);
  pdf.rect(0, 0, 210, 297, 'F');
  pdf.setTextColor(255, 255, 255);
  pdf.setFontSize(24);
  pdf.text(posterElement.dataset.title ?? event.title, 105, 80, { align: 'center' });
  pdf.setFontSize(12);
  pdf.text('IDCS College – Official Event', 105, 260, { align: 'center' });
  pdf.save(`${sanitise(event.title)}_poster.pdf`);
}

// ── Word doc via HTML blob ────────────────────────────────────────────────────

export function downloadPosterAsDoc(event: CollegeEvent): void {
  const guestRows = event.hasChiefGuest
    ? event.chiefGuests
        .map(
          (g, i) =>
            `<tr>
              <td style="padding:4px 8px; border:1px solid #ccc;">${i + 1}</td>
              <td style="padding:4px 8px; border:1px solid #ccc;">${g.name || '—'}</td>
              <td style="padding:4px 8px; border:1px solid #ccc;">${g.imageDataUrl ? '(Photo attached in form)' : '—'}</td>
            </tr>`,
        )
        .join('')
    : '';

  const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8" />
  <title>${event.title}</title>
  <style>
    body { font-family: 'Segoe UI', Calibri, sans-serif; margin: 2cm; color: #1e1b4b; }
    h1   { font-size: 28pt; text-align: center; color: #312e81; margin-bottom: 4pt; }
    h2   { font-size: 14pt; color: #4f46e5; margin-top: 16pt; margin-bottom: 4pt; border-bottom: 1px solid #c7d2fe; padding-bottom: 2pt; }
    p    { font-size: 12pt; margin: 4pt 0; }
    .tag { font-size: 10pt; color: #6d28d9; font-style: italic; text-align: center; }
    table{ border-collapse: collapse; width: 100%; margin-top: 8pt; font-size: 11pt; }
    th   { background: #4f46e5; color: white; padding: 6px 8px; border: 1px solid #4f46e5; }
    footer { margin-top: 40pt; font-size: 9pt; color: #6b7280; text-align: center; }
  </style>
</head>
<body>
  <p class="tag">IDCS College &nbsp;·&nbsp; Official Event Poster</p>
  <h1>${event.title}</h1>

  <h2>Event Details</h2>
  <p><strong>Date &amp; Time:</strong> ${event.dateTime ? new Date(event.dateTime).toLocaleString('en-IN') : 'TBD'}</p>
  <p><strong>Venue:</strong> ${event.venue || 'TBD'}</p>
  <p><strong>Event Coordinators:</strong> ${event.coordinatorCount}</p>
  <p><strong>Status:</strong> ${event.status}</p>

  ${
    event.hasChiefGuest && guestRows
      ? `<h2>Chief Guest(s)</h2>
         <table>
           <tr>
             <th>#</th><th>Name</th><th>Photo</th>
           </tr>
           ${guestRows}
         </table>`
      : ''
  }

  <footer>Generated by IDCS College ERP &nbsp;·&nbsp; Event ID: ${event.id}</footer>
</body>
</html>`;

  const blob = new Blob([html], { type: 'application/msword' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${sanitise(event.title)}_event.doc`;
  a.click();
  URL.revokeObjectURL(url);
}

// ─────────────────────────────────────────────────────────────────────────────

function sanitise(name: string): string {
  return (name || 'event').replace(/[^a-z0-9]/gi, '_').toLowerCase().slice(0, 40);
}
